1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	const BLOCK_SIZE = 3;
4	const BLOCK_BASE_PREMIUM = 60;
5	
6	const BASE_PREMIUM: Record<string, number> = {
7	  sword: 100,
8	  amulet: 60,
9	  staff: 80,
10	  potion: 40,
11	  rune: 25,
12	  moonstone: 25,
13	};
14	
15	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
16	
17	type Item = { type: string; cursed?: boolean; enchantment?: number };
18	const CURSE_RATE = 0.5;
19	const HIGH_ENCHANTMENT_RATE = 0.3;
20	const HIGH_ENCHANTMENT_THRESHOLD = 5;
21	type QuoteStep = { op: "quote"; items: Item[] };
22	type Input = { customer: { yearsWithMHPCO: number }; steps: QuoteStep[] };
23	type QuoteResult = { premium: number };
24	
25	const countByType = (items: Item[]): Map<string, number> => {
26	  const counts = new Map<string, number>();
27	  for (const item of items) {
28	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
29	  }
30	  return counts;
31	};
32	
33	const basePremiumForType = (type: string, count: number): number => {
34	  const unit = BASE_PREMIUM[type];
35	  if (COMPONENT_TYPES.has(type) && count === BLOCK_SIZE) {
36	    return BLOCK_BASE_PREMIUM;
37	  }
38	  return unit * count;
39	};
40	
41	const basePremium = (items: Item[]): number =>
42	  Array.from(countByType(items)).reduce(
43	    (total, [type, count]) => total + basePremiumForType(type, count),
44	    0,
45	  );
46	
47	// MHPCO always rounds premiums in its own favor (up).
48	const roundUpInMHPCOFavor = (amount: number): number => Math.ceil(amount);
49	
50	const itemSurcharge = (item: Item): number => {
51	  const unit = BASE_PREMIUM[item.type];
52	  const curse = item.cursed ? unit * CURSE_RATE : 0;
53	  const highEnch =
54	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
55	      ? unit * HIGH_ENCHANTMENT_RATE
56	      : 0;
57	  return curse + highEnch;
58	};
59	
60	const sumItemSurcharges = (items: Item[]): number =>
61	  items.reduce((total, item) => total + itemSurcharge(item), 0);
62	
63	const quotePremium = (step: QuoteStep): QuoteResult => {
64	  const base = basePremium(step.items);
65	  const surcharges = sumItemSurcharges(step.items);
66	  const firstInsuranceSurcharge = base * FIRST_INSURANCE_RATE;
67	  return {
68	    premium: roundUpInMHPCOFavor(
69	      base + surcharges + firstInsuranceSurcharge + PROCESSING_FEE,
70	    ),
71	  };
72	};
73	
74	export const run = (input: Input): { results: QuoteResult[] } => ({
75	  results: input.steps.map(quotePremium),
76	});
