const isCursed = (item: Item): boolean => item.cursed === true;
const isHighlyEnchanted = (item: Item): boolean =>
  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;

const ITEM_SURCHARGE_RULES: ReadonlyArray<{
  applies: (item: Item) => boolean;
  rate: number;
}> = [
  { applies: isCursed, rate: CURSE_RATE },
  { applies: isHighlyEnchanted, rate: HIGH_ENCHANTMENT_RATE },
];

const itemSurcharge = (item: Item): number => {
  const unit = BASE_PREMIUM[item.type];
  return ITEM_SURCHARGE_RULES.reduce(
    (total, { applies, rate }) => (applies(item) ? total + unit * rate : total),
    0,
  );
};

